1	<script>
2		// Turn the probe until the meter agrees.
3		// probeAngle: primary slider value, degrees, 0..360, step 5.
4		// lengthC1: named auxiliary control, relative length of candidate c1, 0.5..2, step 0.1.
5		let probeAngle = $state(90);
6		let lengthC1 = $state(1);
7	
8		let diagramEl = $state(null);
9	
10		// viewBox is deliberately wider than tall: candidates only ever fan through
11		// the upper half of the circle, so the canvas is cropped to that content
12		// instead of wasting a full square of empty space above the score bars.
13		const VIEW_W = 320;
14		const VIEW_H = 230;
15		const CENTER_X = 160;
16		const CENTER_Y = 150;
17		const R = 50;
18		const MAX_SCORE = 2;
19	
20		const baseCandidates = [
21			{ name: 'c1', angle: 20 },
22			{ name: 'c2', angle: 70 },
23			{ name: 'c3', angle: 110 },
24			{ name: 'c4', angle: 160 }
25		];
26	
27		function computeHead(tipX, tipY, dirX, dirY, shaftLen) {
28			const headLen = shaftLen * 0.18;
29			const halfW = shaftLen * 0.09;
30			const backX = tipX - dirX * headLen;
31			const backY = tipY - dirY * headLen;
32			const perpX = -dirY;
33			const perpY = dirX;
34			const lx = backX + perpX * halfW;
35			const ly = backY + perpY * halfW;
36			const rx = backX - perpX * halfW;
37			const ry = backY - perpY * halfW;
38			return { backX, backY, poly: `${tipX},${tipY} ${lx},${ly} ${rx},${ry}` };
39		}
40	
41		let candidateData = $derived.by(() => {
42			return baseCandidates.map((c) => {
43				const len = c.name === 'c1' ? lengthC1 : 1;
44				const rad = (c.angle * Math.PI) / 180;
45				const dirX = Math.cos(rad);
46				const dirY = -Math.sin(rad);
47				const shaft = R * len;
48				const tipX = CENTER_X + dirX * shaft;
49				const tipY = CENTER_Y + dirY * shaft;
50				const head = computeHead(tipX, tipY, dirX, dirY, shaft);
51				// label offset is measured from the TIP, not from the center, so it
52				// stays a fixed safe distance from the length handle no matter how
53				// long or short c1 gets.
54				const labelR = shaft + 36;
55				const labelX = CENTER_X + dirX * labelR;
56				const labelY = CENTER_Y + dirY * labelR;
57				const diff = ((probeAngle - c.angle) * Math.PI) / 180;
58				const score = Math.cos(diff) * len;
59				return { ...c, len, tipX, tipY, ...head, labelX, labelY, score };
60			});
61		});
62	
63		let probeGeom = $derived.by(() => {
64			const rad = (probeAngle * Math.PI) / 180;
65			const dirX = Math.cos(rad);
66			const dirY = -Math.sin(rad);
67			const shaft = R;
68			const tipX = CENTER_X + dirX * shaft;
69			const tipY = CENTER_Y + dirY * shaft;
70			const head = computeHead(tipX, tipY, dirX, dirY, shaft);
71			const perpX = -dirY;
72			const perpY = dirX;
73			// Pushed well clear of the 44px handle hit box (radial + tangential
74			// combined) so the label never sits under the probe dot or its focus
75			// ring at any angle, including when the probe lands exactly on a
76			// candidate's line.
77			const labelX = CENTER_X + dirX * (R + 48) + perpX * 26;
78			const labelY = CENTER_Y + dirY * (R + 48) + perpY * 26;
79			return { tipX, tipY, ...head, labelX, labelY };
80		});
81	
82		let probeHandlePos = $derived.by(() => ({
83			x: (probeGeom.tipX / VIEW_W) * 100,
84			y: (probeGeom.tipY / VIEW_H) * 100
85		}));
86	
87		let c1HandlePos = $derived.by(() => {
88			const c1 = candidateData.find((c) => c.name === 'c1');
89			return { x: (c1.tipX / VIEW_W) * 100, y: (c1.tipY / VIEW_H) * 100 };
90		});
91	
92		let leaderName = $derived.by(() =>
93			candidateData.reduce((best, c) => (c.score > best.score ? c : best), candidateData[0]).name
94		);
95	
96		function updateProbeFromEvent(e) {
97			if (!diagramEl) return;
98			const rect = diagramEl.getBoundingClientRect();
99			const scaleX = VIEW_W / rect.width;
100			const scaleY = VIEW_H / rect.height;
101			const lx = (e.clientX - rect.left) * scaleX;
102			const ly = (e.clientY - rect.top) * scaleY;
103			const dx = lx - CENTER_X;
104			const dy = ly - CENTER_Y;
105			let deg = (Math.atan2(-dy, dx) * 180) / Math.PI;
106			if (deg < 0) deg += 360;
107			if (deg > 360) deg = 360;
108			probeAngle = deg;
109		}
110	
111		function onProbePointerDown(e) {
112			e.currentTarget.setPointerCapture(e.pointerId);
113			updateProbeFromEvent(e);
114			const move = (ev) => updateProbeFromEvent(ev);
115			const up = () => {
116				window.removeEventListener('pointermove', move);
117				window.removeEventListener('pointerup', up);
118			};
119			window.addEventListener('pointermove', move);
120			window.addEventListener('pointerup', up);
121		}
122	
123		function onProbeKeydown(e) {
124			let handled = true;
125			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') probeAngle = Math.min(360, probeAngle + 5);
126			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') probeAngle = Math.max(0, probeAngle - 5);
127			else if (e.key === 'Home') probeAngle = 0;
128			else if (e.key === 'End') probeAngle = 360;
129			else handled = false;
130			if (handled) e.preventDefault();
131		}
132	
133		function updateLengthFromEvent(e) {
134			if (!diagramEl) return;
135			const rect = diagramEl.getBoundingClientRect();
136			const scaleX = VIEW_W / rect.width;
137			const scaleY = VIEW_H / rect.height;
138			const lx = (e.clientX - rect.left) * scaleX;
139			const ly = (e.clientY - rect.top) * scaleY;
140			const dx = lx - CENTER_X;
141			const dy = ly - CENTER_Y;
142			const dist = Math.sqrt(dx * dx + dy * dy);
143			let len = dist / R;
144			len = Math.min(2, Math.max(0.5, len));
145			lengthC1 = Math.round(len * 10) / 10;
146		}
147	
148		function onLengthPointerDown(e) {
149			e.currentTarget.setPointerCapture(e.pointerId);
150			updateLengthFromEvent(e);
151			const move = (ev) => updateLengthFromEvent(ev);
152			const up = () => {
153				window.removeEventListener('pointermove', move);
154				window.removeEventListener('pointerup', up);
155			};
156			window.addEventListener('pointermove', move);
157			window.addEventListener('pointerup', up);
158		}
159	
160		function onLengthKeydown(e) {
161			let handled = true;
162			if (e.key === 'ArrowRight' || e.key === 'ArrowUp')
163				lengthC1 = Math.min(2, Math.round((lengthC1 + 0.1) * 10) / 10);
164			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown')
165				lengthC1 = Math.max(0.5, Math.round((lengthC1 - 0.1) * 10) / 10);
166			else if (e.key === 'Home') lengthC1 = 0.5;
167			else if (e.key === 'End') lengthC1 = 2;
168			else handled = false;
169			if (handled) e.preventDefault();
170		}
171	</script>
172	
173	<div class="wrap" data-interactive="dot-alignment">
174		<p class="instruction">Drag the probe to score each candidate. Drag c1's handle to change its length.</p>
175	
176		<div class="diagram-wrap" bind:this={diagramEl}>
177			<svg
178				viewBox="0 0 {VIEW_W} {VIEW_H}"
179				class="diagram-svg"
180				role="img"
181				aria-label="Diagram: an amber probe arrow rotates among four periwinkle candidate arrows, c1 through c4"
182			>
183				{#each candidateData as c (c.name)}
184					<line
185						x1={c.tipX}
186						y1={c.tipY}
187						x2={c.tipX}
188						y2={VIEW_H}
189						stroke="var(--data-observed)"
190						stroke-width="1"
191						stroke-dasharray="2,3"
192						opacity="0.22"
193					/>
194					<line
195						x1={CENTER_X}
196						y1={CENTER_Y}
197						x2={c.backX}
198						y2={c.backY}
199						stroke="var(--data-observed)"
200						stroke-width="2.2"
201						stroke-linecap="round"
202					/>
203					<polygon points={c.poly} fill="var(--data-observed)" />
204					<text x={c.labelX} y={c.labelY} class="arrow-label" text-anchor="middle" dominant-baseline="middle">
205						{c.name}
206					</text>
207				{/each}
208	
209				<line
210					x1={CENTER_X}
211					y1={CENTER_Y}
212					x2={probeGeom.backX}
213					y2={probeGeom.backY}
214					stroke="var(--data-heat)"
215					stroke-width="2.2"
216					stroke-linecap="round"
217					class="probe-line"
218				/>
219				<polygon points={probeGeom.poly} fill="var(--data-heat)" />
220				<text
221					x={probeGeom.labelX}
222					y={probeGeom.labelY}
223					class="arrow-label probe-label"
224					text-anchor="middle"
225					dominant-baseline="middle"
226				>
227					probe
228				</text>
229			</svg>
230	
231			<div
232				class="handle probe-handle"
233				style="left: {probeHandlePos.x}%; top: {probeHandlePos.y}%; --handle-color: var(--data-heat);"
234				role="slider"
235				tabindex="0"
236				aria-label="probe angle in degrees"
237				aria-valuemin="0"
238				aria-valuemax="360"
239				aria-valuenow={Math.round(probeAngle)}
240				onpointerdown={onProbePointerDown}
241				onkeydown={onProbeKeydown}
242			></div>
243	
244			<div
245				class="handle length-handle"
246				style="left: {c1HandlePos.x}%; top: {c1HandlePos.y}%; --handle-color: var(--data-observed);"
247				data-control="length-c1"
248				role="spinbutton"
249				tabindex="0"
250				aria-label="c1 length"
251				aria-valuemin="0.5"
252				aria-valuemax="2"
253				aria-valuenow={lengthC1.toFixed(1)}
254				onpointerdown={onLengthPointerDown}
255				onkeydown={onLengthKeydown}
256			></div>
257		</div>
258	
259		<div class="bars">
260			{#each candidateData as c (c.name)}
261				<div class="bar-col">
262					<div class="bar-track">
263						<div class="bar-zero"></div>
264						<div
265							class="bar-fill"
266							class:leading={c.name === leaderName}
267							style="height: {Math.min(Math.abs(c.score) / MAX_SCORE, 1) * 40}px; {c.score >= 0
268								? 'bottom: 50%;'
269								: 'top: 50%;'}"
270						></div>
271					</div>
272					<span class="readout" class:leading={c.name === leaderName}>{Math.round(c.score)}</span>
273					<span class="cand-label">{c.name}</span>
274				</div>
275			{/each}
276		</div>
277	</div>
278	
